const Q_ECONOMICS_2005=[{"id": "objective>Economics>2005>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A profit-maximizing monopolist should produce within the range where his demand is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">elastic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">inelastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">infinitely elastic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">unitary elastic</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is because, in the elastic range of demand curve, a decrease in price leads to a proportionately larger increase in quantity demanded, thereby increasing total revenue. In contrast, if the monopolist produces in the inelastic range, reducing the price would decrease total revenue, as the increase in quantity demanded would be proportionately smaller than the decrease in price. <br/>  <br/> Therefore, to maximize profit, a monoplist will produce where the marginal revenue (MR) is equal to marginal cost (MC) and this typicaly occurs where the demand is elastic.</div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>2005>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  <br/> In the circular flow diagram above, the arrow marked K indicates</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the flow of capital goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">payments to factors of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">payments for goods and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the flow of economic rent</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the diagram, capital goods flow to business firms, labour inputs also flow to business firms, the goods and services produced by the business firms flow to households while the wages also flow to households.</div>", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS"}, {"id": "objective>Economics>2005>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The saving deposit in a commercial bank is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">capital </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fund</div>", "<div style=\"font-family:Cambria;font-size:17px;\">near money </div>", "<div style=\"font-family:Cambria;font-size:17px;\">call money</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The saving deposit in a commercial bank is called near money. Near money refers to highly liquid assets that can quickly be converted into cash. Savings deposits are considered near money because they can be easily withdrawn and used for transactions or converted into cash.</div>", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS"}, {"id": "objective>Economics>2005>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Output Kg</td><td style=\"border:1px solid black;text-align:center;\"> 240</td><td style=\"border:1px solid black;text-align:center;\"> 450</td><td style=\"border:1px solid black;text-align:center;\"> 580</td><td style=\"border:1px solid black;text-align:center;\"> 630 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">MR(N)</td><td style=\"border:1px solid black;text-align:center;\"> 75</td><td style=\"border:1px solid black;text-align:center;\">48</td><td style=\"border:1px solid black;text-align:center;\"> -40</td><td style=\"border:1px solid black;text-align:center;\"> -22 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">MC(N)</td><td style=\"border:1px solid black;text-align:center;\"> 41</td><td style=\"border:1px solid black;text-align:center;\"> 48</td><td style=\"border:1px solid black;text-align:center;\"> 77</td><td style=\"border:1px solid black;text-align:center;\"> 20</td></tr></table></div> <br/> Given the table above, what is the firm's short-run profit-maximizing output?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">450 kg </div>", "<div style=\"font-family:Cambria;font-size:17px;\">630 kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">240 kg </div>", "<div style=\"font-family:Cambria;font-size:17px;\">580 kg</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The firm's short-run profit-maximizing output is where MC = MR. At output 450kg, the marginal cost equals marginal revenue.</div>", "topic": "THE CONCEPT OF COST & REVENUE : PROFIT MAXIMIZATION"}, {"id": "objective>Economics>2005>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The regulatory authority of the capital market in Nigeria is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Central Bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Securities and Exchange Commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigerian Deposit Insurance Corporation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Stock Exchange Market</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Securities and Exchange Commission is the sole regulatory authority of the capital market in Nigeria. The SEC is the apex regulatory body of the NSE.</div>", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC"}, {"id": "objective>Economics>2005>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the long-run, the equilibrium point of a monopolistic firm is a point where the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">marginal cost curve is tangential to the average fixed cost curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand curve is tangential to the average variable cost curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">supply curve is tangential to the marginal cost curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand curve is tangential to the average  cost curve.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Chamberlin, the long-run equilibrium under monopolistic competition is established at the point where the subjec­tive or perceived demand curve is tangent to the long-run average cost curve. <br/>  <br/> </div>", "topic": "MARKET STRUCTURE : MONOPOLISTIC COMPETITION"}, {"id": "objective>Economics>2005>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given that Y = C + I, where ,C = 50 + 0.75 and I = ₦45m, what is the equilibrium level of income?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦380m </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦20m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦180m </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦200m</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Using Y = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">a + I</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\"> 1 - b</span> <br/>  <br/> Where a = 50 (autonomous consumption) <br/>              I = 45 ( investment) <br/>               b = 0.75 ( MPC) <br/>  <br/> Therefore, Y = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">50 + 45</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\"> 1 - 0.75</span> <br/>  <br/>                         = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">95</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">0.25 </span> <br/>  <br/>                            Y = #380m  <br/>  <br/> Alternatively:  <br/> Using Y = C + I  <br/>                Y = 50 + 0.75Y + 45  <br/>                  Y - 0.75Y = 50 + 45  <br/>                     Y - 0.75 = 95 <br/>                     Y( 1 - 0.75)  = 95 <br/>                           Y (0.25) = 95 <br/>                          Y = 95/0.25  <br/>                     = ₦380.</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : ELEMENTARY THEORY OF INCOME DETERMINATION"}, {"id": "objective>Economics>2005>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Above full employment level, an expansionary monetary policy will lead to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a fall in aggregate demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease in aggregate supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fall in the inflation rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rise in the inflation rate</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If expansionary monetary policy occurs when the economy is operating at full employment output, then the money supply increase will eventually put upward pressure on prices. Thus we say that eventually, or in the long run, the aggregate price level will rise and the economy will experience an episode of inflation in the transition.</div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>2005>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major assumption in a perfectly competitive market is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the number of buyers and sellers is small</div>", "<div style=\"font-family:Cambria;font-size:17px;\">individuals cannot influence prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the quality of products remains the same</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prices will always remain constant.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a perfectively competitive market, price is determined by the interaction of the two market forces (demand and supply).it is a market where neither the sellers nor the buyers can influence the ruling price.</div>", "topic": "MARKET STRUCTURE : PERFECT MARKET"}, {"id": "objective>Economics>2005>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A discount house is a market where</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">various bills are exchanged</div>", "<div style=\"font-family:Cambria;font-size:17px;\">short-term and medium-term loans are obtained</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shares are bought and sold</div>", "<div style=\"font-family:Cambria;font-size:17px;\">short-term loans are obtained.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A discount house is a financial institution that specializes in buying and selling short-term debt instruments, such as Treasury bills and commercial paper. They are key players in the money market, where short-term loans are obtained. Therefore, the correct answer is 'short-term loans are obtained.'</div>", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC"}, {"id": "objective>Economics>2005>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Idle cash balances are held for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">planned purchases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the purchase of bonds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the purchase of shares</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unplanned purchases</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Keynes pointed out that a section of people in the community hold cash balances for speculative purposes. This demand for money held under the speculative motive is referred to as the demand for \"idle balances\". The speculative motive for holding cash balances arises from uncertainty about the future rates of interest.</div>", "topic": "MONEY : DEMAND FOR MONEY"}, {"id": "objective>Economics>2005>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a particular year, the sum of the value added in each sector of the economy was ₦4,550 million. The amount represents the GNP measured by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">factor-price approach</div>", "<div style=\"font-family:Cambria;font-size:17px;\">output approach</div>", "<div style=\"font-family:Cambria;font-size:17px;\">income approach</div>", "<div style=\"font-family:Cambria;font-size:17px;\">expenditure approach</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sum of the value added in each sector of the economy represents the GNP measured by the output approach. This method calculates GNP by summing the value  of all goods and services produced in the economy, which is equivalent to summing the value added by all sectors.</div>", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME"}, {"id": "objective>Economics>2005>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Population density is described as the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">average number of people per square kilometer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">average number of people in a country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total population excluding migration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total population including net migration</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Population density can be defined as the number of people per square kilometre of land i.e Pop density = Total population/ Land area</div>", "topic": "POPULATION : POPULATION DENSITY, AGEING POPULATION"}, {"id": "objective>Economics>2005>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The short-run inelasticity of supply of agricultural produce causes</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">stability in prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a steady rise in prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a steady decline in prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">instability in prices</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The short-run inelasticity of supply of agricultural produce refers to a situation where the quantity supplied of agricultural produce does not respond significantly to changes in price in the short run. This is often due to the time lag between the decision to produce and the actual harvest. This inelasticity can cause instability in prices because any change in demand can lead to significant price fluctuations. If demand increases, prices can spike because supply cannot quickly adjust to meet the new demand. Conversely, if demand decreases, prices can drop sharply because the excess supply cannot be quickly reduced.</div>", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES"}, {"id": "objective>Economics>2005>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major contribution of the petroleum industry to the Nigerian economy is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">generation of revenue for the oil companies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provision of employment opportunities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">generation of revenue for government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promotion of industrial harmony</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Petroleum industry generates revenues for the government through the exportation of crude oil and gains from multi-national refinery companies.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : INTRODUCTION"}, {"id": "objective>Economics>2005>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During a conflict between management and workers, the union's bargaining power is based on</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">work-to-rule </div>", "<div style=\"font-family:Cambria;font-size:17px;\">negotiation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">picketing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">management decision</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The process of collective bargaining is based on mistrust and conflict that is, that there is a fundamental divergence of interest between employers and employees. At stake, initially, therefore, is a basis on which the two can agree to cooperate together at all.</div>", "topic": "BUSINESS ORGANISATION : CO-OPERATIVE SOCIETIES"}, {"id": "objective>Economics>2005>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Localization of industries in Nigeria is mainly influenced by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">market size</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population groupings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">raw materials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">external economies</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Localization of industries in Nigeria is mainly influenced by raw materials. Raw materials are materials or substances used in the primary production or manufacturing of goods. Raw materials are often referred to as commodities, which are bought and sold on commodities exchanges worldwide. Industries tend to locate near the source of raw materials to reduce transportation costs.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>2005>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the death rate of a country is 52% and the growth rate is 12%. What is the birth rate of the country?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">48% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">64%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">52%</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The birth rate of a country can be calculated by adding the growth rate to the death rate. In this case, the death rate is 52% and the growth rate is 12%. Therefore, the birth rate is 52% + 12% = 64%.</div>", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE"}, {"id": "objective>Economics>2005>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Agricultural backward-linkage effect means the establishment of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">subsidiary industries to increase the number of industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">main industries to increase output</div>", "<div style=\"font-family:Cambria;font-size:17px;\">industries to reduce imports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">subsidiary industries to feed the main industry</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> The feedback effects generated by a base industry on the development of the base sector is called backward linkage. The development of the food processing industry has many feed back effects on the agriculture sector itself.</div>", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES"}, {"id": "objective>Economics>2005>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The distinction between onshore and offshore operations in oil exploration lies in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">location of sites</div>", "<div style=\"font-family:Cambria;font-size:17px;\">output generated</div>", "<div style=\"font-family:Cambria;font-size:17px;\">size of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">techniques of production</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Onshore refers to activities of oil exploration that are conducted on land away from the ocean while offshore pertains to oil exploration and rigging under the bed of the ocean. The onshore and offshore activities operations are carried out in different location.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : ONSHORE & OFFSHORE OF THE OIL SECTOR"}, {"id": "objective>Economics>2005>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Long-run production is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">diminishing returns to scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">returns to scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">external economies of scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">economies of scale</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The time period during which even/thing (except factor prices and the state of technology or art of production) is variable is called the long run and the associated curve that shows the minimum cost of producing each level of output is called the long- run total cost curve. Return to scale is applicable to the long-run analysis of production.</div>", "topic": "THEORY OF PRODUCTION (2) : CONCEPTS OF PRODUCTION"}, {"id": "objective>Economics>2005>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">For a firm to break even in the long run, the marginal cost curve must cut the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">average variable cost curve at its highest point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">average cost curve at any two lowest points</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total cost curve at its lowest point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">average cost curve at its lowest point</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Break-even takes place where total cost is equal to the total revenue( i.e average cost is equal to average revenue). Therefore, a firm break even in the long run when the MC cuts the AC at its lowest point.</div>", "topic": "THEORY OF PRODUCTION (2) : PRODUCERS EQUILIBRIUM"}, {"id": "objective>Economics>2005>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An increase in the quantity supplied of a commodity suggests</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a leftward shift of the supply curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a rightward shift of the supply curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a movement along the supply curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in elasticity of supply</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Like the law of demand, the law of supply demonstrates the quantities that will be sold at a certain price. But unlike the law of demand, the supply relationship shows an upward slope. This means that the higher the price, the higher the quantity supplied. Producers supply more at a higher price because selling a higher quantity at an higher price increases revenue. <br/> Increase in the quantity supplied implies movement along a supply curve which can only be influenced by change in price of the particular commodity involved.</div>", "topic": "THEORY OF SUPPLY : DISTINCTION BETWEEN CHANGE IN QUANTITY SUPPLIED AND CHANGE IN SUPPLY"}, {"id": "objective>Economics>2005>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a long-run cost of a firm is demonstrated by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fuel and maintenance cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the planned size of plant and equipment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the existing size of plant and equipment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rent on buildings</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Long-run costs are costs that a firm incurs when it increases its production by changing all its inputs. This includes the cost of changing the size of plant and equipment. The planned size of plant and equipment is an example of a long-run cost because it involves a decision that affects the firm's production capacity in the long run.</div>", "topic": "THEORY OF PRODUCTION (1) : SCALE OF PRODUCTION"}, {"id": "objective>Economics>2005>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a car assembly plant, division of labour is demonstrated by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">assigning each worker to a specific activity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">assigning each worker a given number to produce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing the daily output</div>", "<div style=\"font-family:Cambria;font-size:17px;\">producing a specific model</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Division of labour is the specialization of productive activity either by persons in different occupational groups undertaking particular tasks or by dividing a task into its component operations.</div>", "topic": "THEORY OF PRODUCTION (1) : DIVISION OF LABOUR & SPECIALISATION"}, {"id": "objective>Economics>2005>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Under perfect competition, the short-run supply curve of a firm is determined by its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">total cost curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal cost curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">average fixed cost curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">average cost curve</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Under perfect competition, the short-run supply curve of a firm is determined by its marginal cost curve. The marginal cost curve shows the cost of producing one more unit of a good. In the short run, a firm will continue to produce as long as the price it receives for an additional unit of output (marginal revenue) is greater than the cost of producing that additional unit (marginal cost). Therefore, the marginal cost curve above the minimum point of the average variable cost curve is the firm's short-run supply curve.</div>", "topic": "MARKET STRUCTURE : PERFECT MARKET"}, {"id": "objective>Economics>2005>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The hoarding of goods is usually experienced when</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">supply is greater than demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the market price is above the equilibrium price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand is greater than supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess demand is greater than excess supply</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When demand is greater than supply i.e the price is fixed below the equilibrium price, there will be hoarding of goods.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY"}, {"id": "objective>Economics>2005>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The technical relationship between input combination and maximum attainable output is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a production function</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an indifference curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an isocost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an isoquant</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A production function is the technical relationship between inputs and the maximum output that can be produced from those inputs. This relationship can be represented mathematically or graphically. An indifference curve, on the other hand, represents different combinations of goods that a consumer considers equally preferable. An isocost line represents all combinations of inputs that cost the same amount. An isoquant line represents all combinations of inputs that produce the same level of output.</div>", "topic": "THEORY OF PRODUCTION (2) : PRODUCTION FUNCTIONS & LAWS OF RETURNS"}, {"id": "objective>Economics>2005>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the marginal utility of the last unit of commodity X at ₦2 is 16 and that of commodity Y at ₦4 is 24 the consumer will be at equilibrium when</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the price quantity ratios are equal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equal amounts of X and Y are consumed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">less of Y and more of X are consumed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">less of X and more of Y are consumed</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Thus, the equilibrium condition can also be stated as: The consumer is in equilibrium, when the marginal utility of money to the consumer (a) is equal to the ratios of the marginal utilities of the two commodities and their respective prices. Further, individual marginal utilities should be declining..</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM"}, {"id": "objective>Economics>2005>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A buyer who haggles in the market is applying the principle of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">choice </div>", "<div style=\"font-family:Cambria;font-size:17px;\">price mechanism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">opportunity cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">utility maximization</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A buyer haggles in order to beat down the price of a commodity so as to maximize utility and get the highest possible value of money spent.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : UTILITY SCHOOL OF THOUGHT"}, {"id": "objective>Economics>2005>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An inverse relationship between price and quantity demanded implies that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the two variables change in opposite directions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the two variables change in the same direction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">only one variable changes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the two variables remain unchanged</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It implies that there is an inverse relationship between the price and quantity demanded of a commodity,. In other words, other things being equal, quantity demanded will be more at a lower price than at higher price. The law of demand describes the functional relationship between price and quantity demanded.</div>", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2005>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When the marginal utility of a commodity is zero, the total utility is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">at its minimum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">upward-sloping</div>", "<div style=\"font-family:Cambria;font-size:17px;\">downward-sloping</div>", "<div style=\"font-family:Cambria;font-size:17px;\">at its maximum</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The total Utility is at its peak.consumer has reached the maximum level and any extra consumption result to dis-utility.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : DIMINISHING MARGINAL UTILITY AND LAW OF DEMAND"}, {"id": "objective>Economics>2005>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Economic freedom is a basic feature of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a market economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an industrialized economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a planned economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a developing economy</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">There is economic freedom in Free Enterprise Economy as individual is free to invest in any business and every consumer has choice of commodity.it is the feature of a capitalist economy.</div>", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM"}, {"id": "objective>Economics>2005>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><p style=\"padding: 3px;\">Use the table below to answer the question that follows</p>  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Price(₦)</td><td style=\"border:1px solid black;text-align:center;\"> Quantity (Kg) <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">40</td><td style=\"border:1px solid black;text-align:center;\">6 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">48</td><td style=\"border:1px solid black;text-align:center;\">5 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">55</td><td style=\"border:1px solid black;text-align:center;\">4 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">60</td><td style=\"border:1px solid black;text-align:center;\">3 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">70</td><td style=\"border:1px solid black;text-align:center;\">2</td></tr></table></div> <br/>  <br/> What is the median quantity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5kg </div>", "<div style=\"font-family:Cambria;font-size:17px;\">6kg </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3kg </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4kg</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Median = 6+5+4+3+2 <br/>                        = 20 <br/> Therefore, EF/2 <br/>                     = 20/2 <br/>                        = 10th position <br/> Locate where the 10th position lies in the quantity. <br/> Therefore, Median = 5</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY"}, {"id": "objective>Economics>2005>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">Use the table below to answer the question that follows</p>  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Price(₦)</td><td style=\"border:1px solid black;text-align:center;\"> Quantity (Kg) <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">40</td><td style=\"border:1px solid black;text-align:center;\">6 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">48</td><td style=\"border:1px solid black;text-align:center;\">5 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">55</td><td style=\"border:1px solid black;text-align:center;\">4 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">60</td><td style=\"border:1px solid black;text-align:center;\">3 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">70</td><td style=\"border:1px solid black;text-align:center;\">2</td></tr></table></div> <br/> Find the mean price of the distribution</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦54 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦51 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦56 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦59</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">(40 x 6) + (48 x 5) + (55 x 4) + (60 x 3) + (70 x 2)  <br/> = 240 + 240 + 220 + 180 + 140  <br/> = 1020 <br/>  <br/> The total quantity is 6 + 5 + 4 + 3 + 2  <br/> = 20 <br/>  <br/> Now, we divide the sum (1020) by the total quantity (20): <br/>  <br/> 1020 / 20 = 51 <br/>  <br/> Therefore, the mean price of the distribution is ₦51.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY"}, {"id": "objective>Economics>2005>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If elasticity of demand is greater than 1 and less than infinity, demand is said to be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">elastic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">perfectly inelastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inelastic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">perfectly elastic</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Demand is price elastic if a change in price causes a bigger percentage change in demand. It will have a PED greater than one.</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2005>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In economics, production takes place only when</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">producers sell to retailers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">value has been added to a commodity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">modern equipment is used</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumption has taken place.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In economics, production is considered to have taken place when value has been added to a commodity. This could be through the process of manufacturing, processing, or even packaging. The other options do not necessarily indicate that production has taken place.</div>", "topic": "THEORY OF PRODUCTION (1) : INTRODUCTION"}, {"id": "objective>Economics>2005>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The monetization policy of the Nigerian government is aimed at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">encouraging public servants to retire early and become self-employed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transferring government properties to retired public servants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reducing government's burden on the provision of fringe benefits to public servants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">helping governments recover properties held by public servants</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">the monetization policy is aimed at cutting down cost and wastages and equally minimize the rate of careless use of public facilities.</div>", "topic": "FINANCIAL INSTITUTION : INTRODUCTION"}, {"id": "objective>Economics>2005>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The price index computed between two time periods is given as 128%: This implies that the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">disposable incomes have increased by 28%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">living standards have fallen by 128%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">living standards have risen by 128%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">living standards have fallen by 28%</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Price index is always 100%, 128% means that the standard of living has fallen by 28% while the cost of living has risen by 28% since standard of living and cost of living has inverse relationship.i.e 128 - 100 = 28.</div>", "topic": "INFLATION & DEFLATION : EFFECT"}, {"id": "objective>Economics>2005>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The problem of planning in Nigeria is mainly in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">implementation of the plans</div>", "<div style=\"font-family:Cambria;font-size:17px;\">appraisal of the plans</div>", "<div style=\"font-family:Cambria;font-size:17px;\">allocation of scarce resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">articulation of the plans</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The problems associated with economic planning in West Africa are: <br/> - political instability <br/> - inadequate capital <br/> - rapid population growth <br/> - poor implementation plans <br/> - corruption and nepotism etc.</div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}, {"id": "objective>Economics>2005>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The raising of funds by selling stocks to the public is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">equity financing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">deficit financing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">loan financing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debt financing</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The raising of funds by selling stocks to the public is called Equity. Stocks are sometimes called equity because the buyer of the stock has part ownership of the company (that initially issued the stock).</div>", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES"}, {"id": "objective>Economics>2005>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><p style=\"padding: 3px;\">Use the table below to answer the question that follows</p>  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Country </td><td style=\"border:1px solid black;text-align:center;\">Groundnuts(Units)</td><td style=\"border:1px solid black;text-align:center;\">Cocoa(Units) <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Nigeria</td><td style=\"border:1px solid black;text-align:center;\">8000</td><td style=\"border:1px solid black;text-align:center;\">1000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Ghana</td><td style=\"border:1px solid black;text-align:center;\">1000</td><td style=\"border:1px solid black;text-align:center;\">8000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Total Production</td><td style=\"border:1px solid black;text-align:center;\">9000</td><td style=\"border:1px solid black;text-align:center;\">9000</td></tr></table></div> <br/>  <br/> Applying the law of comparative costs, how many units of groundnuts will Nigeria produce?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">7, 000 units </div>", "<div style=\"font-family:Cambria;font-size:17px;\">16, 000 units</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9, 000 units </div>", "<div style=\"font-family:Cambria;font-size:17px;\">8, 000 units</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Opportunity Cost of 1 unit of Groundnuts in Nigeria = (What Nigeria gives up/Produces) <br/>  <br/> Opportunity Cost of 1 unit of Groundnuts in Nigeria = (1000 units of Cocoa)/(8000 units of Groundnuts) = 1/8 units of Cocoa <br/>  <br/> Opportunity Cost of 1 unit of Groundnuts in Ghana = (What Ghana gives up/Produces) <br/>  <br/> Opportunity Cost of 1 unit of Groundnuts in Ghana = (8000 units of Cocoa)/(1000 units of Groundnuts) = 8 units of Cocoa <br/>  <br/> Nigeria has a lower opportunity cost for producing groundnuts (1/8 units of Cocoa) compared to Ghana (8 units of Cocoa). Therefore, Nigeria has a comparative advantage in the production of groundnuts. <br/>  <br/> So, Nigeria should produce groundnuts. The quantity it should produce is equal to its initial production of groundnuts, which is 8,000 units.</div>", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE"}, {"id": "objective>Economics>2005>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">Use the table below to answer the question that follows</p>  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Country </td><td style=\"border:1px solid black;text-align:center;\">Groundnuts(Units)</td><td style=\"border:1px solid black;text-align:center;\">Cocoa(Units) <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Nigeria</td><td style=\"border:1px solid black;text-align:center;\">8000</td><td style=\"border:1px solid black;text-align:center;\">1000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Ghana</td><td style=\"border:1px solid black;text-align:center;\">1000</td><td style=\"border:1px solid black;text-align:center;\">8000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Total Production</td><td style=\"border:1px solid black;text-align:center;\">9000</td><td style=\"border:1px solid black;text-align:center;\">9000</td></tr></table></div> <br/> The difference in each country's total output on specialization is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">16,000 units </div>", "<div style=\"font-family:Cambria;font-size:17px;\">9,000 units</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8,000 units </div>", "<div style=\"font-family:Cambria;font-size:17px;\">7,000 units</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For groundnuts: <br/> Nigeria's total groundnut production: 8000 units <br/> Ghana's total groundnut production: 1000 units <br/>  <br/> Difference in groundnut production: 8000 - 1000  <br/> = 7000 units <br/>  <br/> For cocoa: <br/> Nigeria's total cocoa production: 1000 units <br/> Ghana's total cocoa production: 8000 units <br/>  <br/> Difference in cocoa production: 8000 - 1000 <br/>  = 7000 units</div>", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE"}, {"id": "objective>Economics>2005>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The loans from the World Bank to developing countries are mainly to support</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">capital-intensive technology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the establishment of universities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">their infrastructural investment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">their level of consumption</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The World Bank gives long-term loan to developing countries to assist them in financing their infrastructural projects.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC"}, {"id": "objective>Economics>2005>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Economic growth is different from economic development because economic growth</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">describes expansion and change</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is measurable but not objective</div>", "<div style=\"font-family:Cambria;font-size:17px;\">describes expansion and not change</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is not measurable but objective</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Economic growth is a much narrow concept than economic development because it focuses on a single dimension, the GDP. In contrast, economic development is a broader concept that focuses on multiple dimensions including people's income as well as their quality of life.</div>", "topic": "ECONOMIC DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT"}, {"id": "objective>Economics>2005>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A long-term capital outflow is recorded in the balance of payments as a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">credit on the capital account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">credit on the current account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debit on the current account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debit on the capital account</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Whenever a country has an outflow of funds, it is recorded as a debit on the balance of payments. When all components of the BOP accounts are included they must sum to zero with no overall surplus or deficit.</div>", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT"}, {"id": "objective>Economics>2005>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Business organization in which the owner's personal property may be forfeited in the event of bankruptcy are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">partnerships and limited liability companies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">partnerships and sole proprietorships</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cooperatives and limited liability companies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">corporations and sole proprietorships</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Partnership and sole-proprietorship business organizations have the feature of unlimited liability which implies that in the event of failure, the owners may forfeit their personal properties.</div>", "topic": "BUSINESS ORGANISATION : PARTNERSHIP~~BUSINESS ORGANISATION : SOLE PROPRIETOSHIP~~BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES"}, {"id": "objective>Economics>2005>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The factor responsible for the current inflationary pressures in Nigeria is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">exchange rate depreciation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in exports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low per capital income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">budget surplus</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The persistent depreciation in the exchange rate of naira makes the value of naira to fall and this makes the goods and services to be costlier.</div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>2005>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If government increases its expenditure on public works, the desired effect is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a reduction in the use of capital equipment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in the level of employment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in the level of inflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in the use of capital equipment</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As a result of public expenditure,capacity to work and save tends to rise.Government expenditure provides various kinds of social and economic facilities stimulating the capacity to work of the people.Increased capacity implies increased efficiency and greater employment.</div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}, {"id": "objective>Economics>2005>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An institution that regulates trade relations among members is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ADB </div>", "<div style=\"font-family:Cambria;font-size:17px;\">OPEC </div>", "<div style=\"font-family:Cambria;font-size:17px;\">EU </div>", "<div style=\"font-family:Cambria;font-size:17px;\">IMF</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">EU policies aim to ensure the free movement of people, goods, services and capital within the internal market; enact legislation in justice and home affairs; and maintain common policies on trade, agriculture, fisheries and regional development.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : OPEC, ECA, IMF"}];
